-- Icon Kids — templates de boas-vindas no inicio da sessao
--
-- Disparados pelo painel quando uma crianca e cadastrada pra brincar:
-- WhatsApp curtinho + Email bonito com o link do termo de
-- responsabilidade pra assinatura.

insert into public.message_templates (key, name, body) values
  (
    'wa_session_welcome',
    '[WA] Boas-vindas + termo',
    E'Oi {{nome}}! 💙 A {{crianca}} chegou pra brincar no iCOM Kids. Sessao de {{tempo}} min comecando agora!\n\nAntes da diversao, leia e assine nosso termo de responsabilidade (leva 1 minuto):\n\n👉 {{link}}\n\nQualquer coisa estamos por aqui. ✨'
  ),
  (
    'email_session_welcome',
    '[Email] Boas-vindas + termo',
    E'<!doctype html>\n<html lang="pt-BR">\n  <head>\n    <meta charset="UTF-8" />\n    <title>Boas-vindas ao iCOM Kids!</title>\n  </head>\n  <body style="margin:0;padding:0;background:#f6f7fb;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;color:#0f172a;">\n    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f6f7fb;padding:32px 16px;">\n      <tr>\n        <td align="center">\n          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:560px;background:#ffffff;border-radius:18px;overflow:hidden;box-shadow:0 6px 24px rgba(15,23,42,0.08);">\n            <tr>\n              <td style="background:linear-gradient(135deg,#1E78DC 0%,#3CB4E0 50%,#A6CD3F 100%);padding:32px 28px;text-align:center;">\n                <p style="margin:0;color:#ffffff;font-size:11px;font-weight:700;letter-spacing:4px;text-transform:uppercase;">iCOM Kids</p>\n                <p style="margin:8px 0 0;color:#ffffff;font-size:28px;font-weight:900;line-height:1.1;">Bem-vindo,<br/>{{nome}}! 🛝</p>\n              </td>\n            </tr>\n            <tr>\n              <td style="padding:32px 28px;">\n                <p style="margin:0 0 16px;font-size:16px;line-height:1.5;color:#0f172a;">A <strong>{{crianca}}</strong> chegou agora pra brincar no iCOM Kids. Sessao de <strong>{{tempo}} minutos</strong> rodando!</p>\n                <p style="margin:0 0 24px;font-size:16px;line-height:1.5;color:#0f172a;"><strong>Antes da diversao começar:</strong> leia e assine nosso termo de responsabilidade. Leva 1 minutinho no celular.</p>\n                <table role="presentation" cellpadding="0" cellspacing="0" style="margin:0 auto;">\n                  <tr>\n                    <td align="center" style="background:#1E78DC;border-radius:999px;">\n                      <a href="{{link}}" style="display:inline-block;padding:14px 36px;color:#ffffff;font-weight:700;font-size:15px;text-decoration:none;letter-spacing:0.5px;">Assinar o termo →</a>\n                    </td>\n                  </tr>\n                </table>\n                <p style="margin:24px 0 0;font-size:13px;line-height:1.5;color:#64748b;text-align:center;">Se o botao nao funcionar, copie e cole no navegador:<br/><a href="{{link}}" style="color:#1E78DC;word-break:break-all;">{{link}}</a></p>\n              </td>\n            </tr>\n            <tr>\n              <td style="padding:0 28px;">\n                <hr style="border:none;border-top:1px solid #e2e8f0;margin:0;" />\n              </td>\n            </tr>\n            <tr>\n              <td style="padding:24px 28px;text-align:center;">\n                <p style="margin:0;color:#94a3b8;font-size:11px;letter-spacing:3px;text-transform:uppercase;font-weight:700;">Diversao em movimento</p>\n                <p style="margin:12px 0 0;color:#64748b;font-size:11px;">iCOM Kids · contato@icomkids.com.br</p>\n              </td>\n            </tr>\n          </table>\n        </td>\n      </tr>\n    </table>\n  </body>\n</html>'
  )
on conflict (key) do update set body = excluded.body, name = excluded.name;
